@patch
@torch.no_grad()
def evaluate_dataset_fixed_t0(self: MultiAgentGoalEvaluator, make_env: Callable[[], Any],
                                num_episodes=None, max_steps=150, t0=None,
                                batch_size=8):
    """
    Runs evaluate_batch_fixed_t0 over chunks of `batch_size` episodes from
    the val dataset (each chunk run in parallel through its own
    MultiAgentEnvPool), aggregating embedding distance-to-goal and
    success by real step index across all episodes.

    Args:
        make_env: zero-arg factory building one fresh multi-agent env
            instance (e.g. `lambda: PettingZooWrapper(MultiGridEnv(...))`).
            Called `batch_size` times to build the pool.
        batch_size: number of episodes evaluated in parallel per chunk
            (mirrors CEMSolver's own `batch_size` chunking convention).
        t0: if None, defaults to history_size - 1 per episode. If an int,
            used as a fixed absolute t0 for every episode (episodes too
            short for it are skipped).

    NOTE: assumes the dataloader yields batch_size=1 (single episode per
    batch); episodes are buffered here and stacked into chunks of
    `batch_size` before being handed to the pool.
    """
    dataset = self.data_module.val_dataloader()
    assert dataset.batch_size == 1, "evaluate_dataset_fixed_t0 requires the dataloader's own batch_size=1"

    per_agent_step_dist = {agent: defaultdict(list) for agent in self.agents}
    per_agent_step_success = {agent: defaultdict(list) for agent in self.agents}

    pool = MultiAgentEnvPool([make_env for _ in range(batch_size)], agents=self.agents)

    n_evaluated = 0
    chunk_buffer = []

    def flush_chunk(chunk):
        nonlocal n_evaluated
        n = len(chunk)
        episodes = {
            "goal_pos": torch.stack([c["goal_pos"] for c in chunk]),
            "goal_obs": torch.stack([c["goal_obs"] for c in chunk]),
        }
        for agent in self.agents:
            episodes[agent] = {
                k: torch.cat([c[agent][k] for c in chunk], dim=0)
                for k in chunk[0][agent]
            }
        t0s = np.array([c["t0"] for c in chunk])

        # pool was built for `batch_size`; if this is a short final chunk,
        # only use the first `n` env slots.
        sub_pool = pool if n == pool.num_envs else _SubPool(pool, n)

        ep_res = self.evaluate_batch_fixed_t0(episodes, sub_pool, t0s, max_steps=max_steps)
        n_evaluated += n
        for agent in self.agents:
            for (i, step), dist, reached in zip(
                ep_res[agent]["step"], ep_res[agent]["embedding_dist_to_goal"], ep_res[agent]["reached"]
            ):
                per_agent_step_dist[agent][step].append(dist)
                per_agent_step_success[agent][step].append(float(reached))

    for i, batch in enumerate(dataset):
        if num_episodes is not None and n_evaluated + len(chunk_buffer) >= num_episodes:
            break

        length = batch["length"][0].item()
        this_t0 = (self.history_size - 1) if t0 is None else t0
        if this_t0 >= length:
            print(f"Skipping episode {i}: length={length} too short for t0={this_t0}")
            continue

        episode = {
            "goal_pos": batch["goal_pos"][0],
            "goal_obs": batch["goal_obs"][0],
            "t0": this_t0,
        }
        H = self.history_size
        goal_obs = episode["goal_obs"]  # (num_agents, C, H, W) or (num_agents, 1, C, H, W)
        for ai, agent in enumerate(self.agents):
            a_batch = batch[self.dataset_agent_keys[agent]]
            goal_frame = goal_obs[ai] if goal_obs.dim() == 5 else goal_obs[ai:ai + 1]
            # Slice down to fixed-size windows HERE, per episode, before
            # any cross-episode concatenation -- episode lengths vary
            # (that's what caused the cat() size mismatch), but a
            # history window of length H and single-step slices at t0
            # are the same size for every episode.
            episode[agent] = {
                "pixels_hist": a_batch["pixels"][0:1, this_t0 - H + 1: this_t0 + 1],
                "action_hist": a_batch["action"][0:1, this_t0 - H + 1: this_t0 + 1],
                "goal_pixels": goal_frame,  # (1, C, H, W): real dataset goal, matches original goal_override
                "pos_t0": a_batch["pos"][0:1, this_t0],
                "dir_t0": a_batch["dir"][0:1, this_t0],
                "pov_vqvae_t0": a_batch["pov_seq_vqvae"][0:1, this_t0],
                "csi_t0": a_batch["csi"][0:1, this_t0],
            }
        chunk_buffer.append(episode)

        if len(chunk_buffer) == batch_size:
            print(f"Evaluating chunk of {batch_size} episodes in parallel (max_steps={max_steps})...")
            flush_chunk(chunk_buffer)
            chunk_buffer = []

    if chunk_buffer:
        print(f"Evaluating final chunk of {len(chunk_buffer)} episodes in parallel...")
        flush_chunk(chunk_buffer)

    curves = {}
    for agent in self.agents:
        steps = sorted(per_agent_step_dist[agent].keys())
        curves[agent] = {
            "step": steps,
            "mean_embedding_dist": [float(torch.tensor(per_agent_step_dist[agent][s]).mean()) for s in steps],
            "std_embedding_dist": [float(torch.tensor(per_agent_step_dist[agent][s]).std()) for s in steps],
            "success_rate": [float(torch.tensor(per_agent_step_success[agent][s]).mean()) for s in steps],
        }

    for agent in self.agents:
        c = curves[agent]
        wandb.log({
            f"eval/{agent}/embedding_dist_vs_realstep": wandb.plot.line(
                wandb.Table(data=list(zip(c["step"], c["mean_embedding_dist"])), columns=["step", "mean_dist"]),
                x="step", y="mean_dist", title=f"{agent} embedding distance to goal vs real step (fixed t0)",
            ),
            f"eval/{agent}/success_rate_vs_realstep": wandb.plot.line(
                wandb.Table(data=list(zip(c["step"], c["success_rate"])), columns=["step", "success_rate"]),
                x="step", y="success_rate", title=f"{agent} cumulative success rate vs real step (fixed t0)",
            ),
        })

    return curves


