class _SubPool:
    """Thin view exposing only the first `n` env slots of a larger pool, for
    a short final chunk that doesn't fill the whole pool. Avoids rebuilding
    (and re-instantiating, which may be expensive) the pool for the tail end
    of a dataset that isn't an exact multiple of batch_size."""
 
    def __init__(self, pool: MultiAgentEnvPool, n: int):
        self._pool = pool
        self._n = n
 
    @property
    def num_envs(self):
        return self._n
 
    @property
    def envs(self):
        return self._pool.envs[: self._n]
 
    def reset(self, seed=None, options=None, mask=None):
        full_mask = np.zeros(self._pool.num_envs, dtype=bool)
        full_mask[: self._n] = True if mask is None else mask
        return self._pool.reset(seed=seed, options=options, mask=full_mask)
 
    def step(self, actions, mask=None, noop_action= 3):
        full_mask = np.zeros(self._pool.num_envs, dtype=bool)
        full_mask[: self._n] = True if mask is None else mask
        full_actions = {
            a: np.concatenate([v, np.zeros(self._pool.num_envs - self._n, dtype=v.dtype)])
            for a, v in actions.items()
        }
        return self._pool.step(full_actions, mask=full_mask, noop_action=noop_action)
 


